acceptance_tests.test_meter.py:
import pytest
from meter import cost, DEFAULT_RATE_CARD

def test_basic_gpt4():
    usage = {'input_tokens': 1000, 'output_tokens': 1000}
    rate_card = {'gpt-4': {'input': 0.03, 'output': 0.06}}
    result = cost('gpt-4', usage, rate_card)
    assert result == round(0.03 + 0.06, 4)

def test_unknown_model_raises():
    usage = {'input_tokens': 100, 'output_tokens': 100}
    with pytest.raises(ValueError):
        cost('unknown-model', usage, {'gpt-4': {'input': 0.03, 'output': 0.06}})

def test_default_rate_card_used_when_none():
    usage = {'input_tokens': 1000, 'output_tokens': 0}
    result = cost('gpt-4', usage, None)
    assert isinstance(result, float)
    assert 'gpt-4' in DEFAULT_RATE_CARD

def test_volume_discount_applied():
    usage = {'input_tokens': 60000, 'output_tokens': 60000}
    rate_card = {'m': {'input': 1.0, 'output': 1.0}}
    result = cost('m', usage, rate_card)
    raw = (60000/1000)*1.0 + (60000/1000)*1.0
    expected = round(raw * 0.9, 4)
    assert result == expected

def test_no_discount_under_threshold():
    usage = {'input_tokens': 1000, 'output_tokens': 1000}
    rate_card = {'m': {'input': 1.0, 'output': 1.0}}
    result = cost('m', usage, rate_card)
    assert result == round(1.0 + 1.0, 4)

